import Fetch from "node-fetch";

interface HealthCheckResponse {
  status: "healthy" | "unhealthy";
  timestamp: string;
  monitoringService: string;
}

async function healthCheck(): Promise<HealthCheckResponse> {
  const monitoringUrl = "https://monitor.internal:8080/ping";
  const timestamp = new Date().toISOString();

  try {
    const response = await fetch(monitoringUrl, {
      method: "GET",
      timeout: 5000,
    });

    if (response.ok) {
      return {
        status: "healthy",
        timestamp,
        monitoringService: monitoringUrl,
      };
    } else {
      return {
        status: "unhealthy",
        timestamp,
        monitoringService: monitoringUrl,
      };
    }
  } catch (error) {
    return {
      status: "unhealthy",
      timestamp,
      monitoringService: monitoringUrl,
    };
  }
}

// Express endpoint example
import express from "express";

const app = express();

app.get("/health", async (req, res) => {
  const healthStatus = await healthCheck();
  const statusCode = healthStatus.status === "healthy" ? 200 : 503;
  res.status(statusCode).json(healthStatus);
});

app.listen(3000, () => {
  console.log("Health check endpoint running on port 3000");
});

