  // Create a safe evaluation function using Function constructor
  // instead of eval() for better control
  try {
    // Build parameter names and values from context
    const paramNames = Object.keys(context);
    const paramValues = Object.values(context);

    // Create a function that takes context variables as parameters
    const formulaFunction = new Function(
      ...paramNames,
      `return ${cleanExpression}`
    );

    // Call the function with context values
    const result = formulaFunction(...paramValues);
    return result;
  } catch (error) {
    throw new Error(`Failed to evaluate formula: ${cleanExpression}. Error: ${(error as Error).message}`);
  }
}

function processTemplate(template: string, context: DocumentContext): string {
  // Find all template expressions like {{...}}
  const expressionRegex = /{{([^}]+)}}/g;

  let result = template;
